# Return search results from tool call for dynamic RAG
{
  "type": "tool_result",
  "tool_use_id": "tool_123",
  "content": [
    {
      "type": "search_result",
      "source": "https://docs.company.com/guide",
      "title": "User Guide",
      "content": [{"type": "text", "text": "Important content..."}],
      "citations": {"enabled": true}
    }
  ]
}

