{
  "type": "user",
  "content": [
    {
      "type": "search_result",
      "source": "https://docs.company.com/guide",
      "title": "User Guide",
      "content": [{"type": "text", "text": "Important content..."}],
      "citations": {"enabled": true}
    }
  ]
}

{
  "type": "search_result",
  "citations": {
    "enabled": true  // Enable citations for this result
  }
}
